// ---- Pillar 1: Keyword Research — Groq-powered expansion → Supabase ----
// Input: { seeds: ['latam market entry', 'ai marketing'] } (optional — uses defaults)
// Replaced Google Suggest (blocked on VPS datacenter IPs) with direct Groq expansion.
// Groq expands each seed into 6-8 related search queries, then clusters and scores them.
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const DEFAULT_SEEDS = [
  'latam market entry', 'latin america b2b marketing', 'mexico market strategy',
  'ai marketing implementation', 'ai sales marketing', 'b2b ai tools marketing',
  'go-to-market strategy b2b', 'gtm consulting', 'revenue growth b2b', 'b2b pipeline strategy',
  'latam expansion consulting', 'growth marketing consulting'
];
const seeds = (Array.isArray(b.seeds) && b.seeds.length) ? b.seeds : DEFAULT_SEEDS;

// 1) Groq: expand seeds + cluster + score in one call
const SYSTEM = `You are an SEO strategist for Markexis, a B2B consulting firm specialising in:
1. LatAm Market Entry (Mexico, Brazil, Colombia, Argentina, Chile)
2. AI Implementation in Marketing & Sales
3. Revenue Growth & GTM Strategy

For each seed keyword provided, generate 6-8 realistic search queries that a potential B2B client would type into Google. Focus on commercial and investigational intent (not pure informational). Include long-tail variations, question formats, and comparison queries.

Then classify every generated keyword. Return ONLY valid JSON:
{
  "keywords": [
    { "keyword": "...", "cluster": "latam|ai|gtm|competitor", "intent": "commercial|informational|navigational", "priority": 1-10, "pillar": "latam|ai|gtm" }
  ]
}
Only include keywords with priority >= 6. Prioritise commercial intent (priority 8-10). Informational but high-volume gets priority 6-7.`;

const USER = `Expand and classify these seed keywords for Markexis:\n${seeds.join('\n')}`;

let parsed = { keywords: [] };
const providers = [
  { url: 'https://api.groq.com/openai/v1/chat/completions', key: ENV.GROQ_API_KEY, model: 'llama-3.1-8b-instant' },
  { url: 'https://api.cerebras.ai/v1/chat/completions', key: ENV.CEREBRAS_API_KEY, model: 'llama3.1-70b' },
  { url: 'https://api.sambanova.ai/v1/chat/completions', key: ENV.SAMBANOVA_API_KEY, model: 'Meta-Llama-3.1-405B-Instruct' },
];
for (const p of providers) {
  if (!p.key) continue;
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST', url: p.url,
      headers: { Authorization: `Bearer ${p.key}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: p.model, messages: [{role:'system',content:SYSTEM},{role:'user',content:USER}], temperature: 0.3, max_tokens: 4096, response_format: { type: 'json_object' } }),
      json: true, timeout: 45000
    });
    parsed = JSON.parse(res.choices[0].message.content);
    break;
  } catch { continue; }
}

const toStore = (parsed.keywords || []).filter(k => k.keyword && k.priority >= 6);
if (!toStore.length) return [{ json: { ok: false, error: 'Groq returned no keywords', seeds_used: seeds.length } }];

// 2) Batch upsert into Supabase keywords table
const upserts = await Promise.allSettled(toStore.map(kw =>
  this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/keywords?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify({
      keyword: kw.keyword, pillar: kw.pillar, cluster: `cluster_${kw.cluster}`,
      priority_score: kw.priority, kd: null, volume: null,
      last_checked: new Date().toISOString()
    }),
    json: false, timeout: 15000
  })
));

const stored = upserts.filter(r => r.status === 'fulfilled').length;
return [{ json: { ok: true, seeds_used: seeds.length, generated: toStore.length, stored, sample: toStore.slice(0, 5).map(k => k.keyword) } }];
